-- Program: Batsman Endurance
-- Category: Sports -> sport_specific
-- Priority: Low
-- Durations: [4, 8], Sessions: [4, 5]

-- Insert branded program
INSERT INTO branded_programs (
    name, description, category, difficulty_level,
    duration_weeks, sessions_per_week, split_type,
    goals, requires_gym, is_active
) VALUES (
    'Batsman Endurance',
    'Long innings conditioning with focus on running between wickets and shot power',
    'sport_specific',
    'all_levels',
    8,
    5,
    'circuit',
    ARRAY['Build cardiovascular endurance', 'Improve VO2 max', 'Improve athletic performance', 'Develop explosiveness']::text[],
    true,
    true
) ON CONFLICT (name) DO UPDATE SET
    description = EXCLUDED.description,
    category = EXCLUDED.category,
    difficulty_level = EXCLUDED.difficulty_level,
    duration_weeks = EXCLUDED.duration_weeks,
    sessions_per_week = EXCLUDED.sessions_per_week,
    split_type = EXCLUDED.split_type,
    goals = EXCLUDED.goals,
    requires_gym = EXCLUDED.requires_gym,
    updated_at = NOW();

-- Variant: Batsman Endurance - 4w 4x/wk
INSERT INTO program_variants (
    base_program_id,
    intensity_level,
    duration_weeks,
    variant_name,
    program_category,
    sessions_per_week,
    session_duration_minutes,
    goals,
    workouts
) SELECT
    bp.id,
    'Medium',
    4,
    'Batsman Endurance - 4w 4x/wk',
    'sport_specific',
    4,
    60,
    ARRAY['Build cardiovascular endurance', 'Improve VO2 max', 'Improve athletic performance', 'Develop explosiveness']::text[],
    '[]'::jsonb
FROM branded_programs bp
WHERE bp.name = 'Batsman Endurance'
ON CONFLICT DO NOTHING;

